import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App.jsx';
import './index.css';

ReactDOM.createRoot(document.getElementById('root')).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useEffect, useState } from "react";
import Provider from "@magicbell/react/context-provider";
import FloatingInbox from "@magicbell/react/floating-inbox";
import "@magicbell/react/styles/floating-inbox.css";
import "./App.css";

function App() {
  const [token, setToken] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch("/token")
      .then((res) => {
        if (!res.ok) {
          throw new Error(`HTTP error! status: ${res.status}`);
        }
        return res.json();
      })
      .then((data) => {
        if (data.token) {
          setToken(data.token);
        } else {
          setError("No token returned from backend");
        }
      })
      .catch((err) => {
        console.error("Failed to fetch MagicBell token:", err);
        setError(err.message);
      });
  }, []);

  return (
    <div className="app-container">
      <header className="header">
        <div className="logo-container">
          <span className="logo-text">SaaS Dashboard</span>
        </div>
        <div className="actions-container">
          {error && <span className="error-message">Error: {error}</span>}
          {!token && !error && <span className="loading-message">Fetching token...</span>}
          {token && (
            <Provider token={token}>
              <FloatingInbox placement="bottom-end" />
            </Provider>
          )}
        </div>
      </header>
      <main className="main-content">
        <div className="dashboard-card">
          <h1>Welcome to your SaaS Dashboard</h1>
          <p>
            This demo showcases the integration of the modern <code>@magicbell/react</code> FloatingInbox with a custom Node.js Express backend.
          </p>
          <div className="status-box">
            <h3>Connection Status:</h3>
            {token ? (
              <p className="status-success">✓ MagicBell Provider successfully initialized with User JWT.</p>
            ) : (
              <p className="status-pending">⚡ Waiting for User JWT...</p>
            )}
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;

body {
  margin: 0;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
  background-color: #f3f4f6;
  color: #1f2937;
}

.app-container {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2rem;
  background-color: #ffffff;
  box-shadow: 0 1px 3px 0 rgba(0, 0, 0, 0.1), 0 1px 2px 0 rgba(0, 0, 0, 0.06);
}

.logo-text {
  font-size: 1.25rem;
  font-weight: 700;
  color: #4f46e5;
}

.actions-container {
  display: flex;
  align-items: center;
  gap: 1rem;
}

.error-message {
  color: #ef4444;
  font-size: 0.875rem;
}

.loading-message {
  color: #6b7280;
  font-size: 0.875rem;
}

.main-content {
  flex-grow: 1;
  padding: 3rem 2rem;
  max-width: 800px;
  margin: 0 auto;
  width: 100%;
}

.dashboard-card {
  background: #ffffff;
  padding: 2.5rem;
  border-radius: 0.5rem;
  box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
}

.dashboard-card h1 {
  margin-top: 0;
  font-size: 1.875rem;
  color: #111827;
}

.dashboard-card p {
  color: #4b5563;
  line-height: 1.6;
}

.status-box {
  margin-top: 2rem;
  padding: 1.25rem;
  background-color: #f9fafb;
  border-radius: 0.375rem;
  border: 1px solid #e5e7eb;
}

.status-box h3 {
  margin-top: 0;
  margin-bottom: 0.5rem;
  font-size: 1rem;
  color: #374151;
}

.status-success {
  color: #10b981;
  font-weight: 600;
  margin: 0;
}

.status-pending {
  color: #f59e0b;
  font-weight: 600;
  margin: 0;
}

